/**
 * KaTeX math rendering for node/label content.
 *
 * Detects $...$ delimiters in labels and renders them via KaTeX
 * into <foreignObject> for SVG embedding. Falls back to plain <text>
 * when KaTeX is not loaded.
 *
 * KaTeX is an optional dependency — load via CDN:
 *   <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/katex@0.16.22/dist/katex.min.css">
 *   <script src="https://cdn.jsdelivr.net/npm/katex@0.16.22/dist/katex.min.js"></script>
 */

const SVG_NS = 'http://www.w3.org/2000/svg';
const XHTML_NS = 'http://www.w3.org/1999/xhtml';

/** Regex: at least one $...$ pair (not escaped, not single $). */
const MATH_REGEX = /\$([^$]+)\$/;

/**
 * Check if a label contains $...$ math content.
 * @param {*} label
 * @returns {boolean}
 */
export function isMathLabel(label) {
  if (label == null || typeof label !== 'string' || label === '') return false;
  return MATH_REGEX.test(label);
}

/**
 * Strip $ delimiters from a label (for fallback plain-text rendering).
 * @param {string} label
 * @returns {string}
 */
export function stripMath(label) {
  if (typeof label !== 'string') return String(label ?? '');
  return label.replace(/\$([^$]+)\$/g, '$1');
}

/**
 * Check if KaTeX is loaded in the current environment.
 * @returns {boolean}
 */
export function isKaTeXAvailable() {
  return !!(typeof window !== 'undefined' && window.katex && typeof window.katex.renderToString === 'function');
}

// User-defined KaTeX macros, applied to every math render until overridden.
// Set via setKatexMacros() at the start of render() in index.js.
let _katexMacros = {};

/**
 * Register user-defined KaTeX macros for subsequent math rendering.
 * Passing null or an empty object clears the registry.
 * @param {Object|null} macros - e.g. { "\\pay": "\\phantom{-}#1,#2" }
 */
export function setKatexMacros(macros) {
  _katexMacros = macros && typeof macros === 'object' ? macros : {};
}

/**
 * Render a math label to KaTeX HTML string.
 * Handles mixed text+math: segments outside $...$ are plain text,
 * segments inside are rendered as math.
 * @param {string} label
 * @returns {string} HTML string
 */
function renderMathToHTML(label) {
  const parts = label.split(/(\$[^$]+\$)/);
  let html = '';
  for (const part of parts) {
    if (part.startsWith('$') && part.endsWith('$')) {
      const tex = part.slice(1, -1);
      try {
        html += window.katex.renderToString(tex, {
          throwOnError: false,
          displayMode: false,
          macros: _katexMacros,
        });
      } catch {
        html += escapeHTML(tex);
      }
    } else {
      html += escapeHTML(part);
    }
  }
  return html;
}

function escapeHTML(str) {
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// ── Off-screen measurement ──────────────────────────────

let _measureDiv = null;

/**
 * Get or create the off-screen measurement div.
 * @returns {HTMLDivElement}
 */
function getMeasureDiv() {
  if (_measureDiv && _measureDiv.parentNode) return _measureDiv;
  _measureDiv = document.createElement('div');
  _measureDiv.style.cssText = 'position:absolute;left:-9999px;top:-9999px;visibility:hidden;';
  document.body.appendChild(_measureDiv);
  return _measureDiv;
}

/**
 * Measurement cache keyed by fontSize + HTML. KaTeX metrics change once the
 * web fonts arrive; entries are invalidated and re-measured on every KaTeX
 * `loadingdone` (see flushFontCorrection) rather than trusting a single
 * `document.fonts.ready` event. That event is an unreliable proxy for "the
 * KaTeX faces are usable" — the faces are lazy and a CDN katex.min.css may
 * still be parsing, so it can resolve before KaTeX_Main/KaTeX_Math exist.
 * Trusting it once both pinned wrong (fallback) metrics and cancelled the one
 * corrective re-render, collapsing every label to the origin. See
 * katex-font-collapse-bug.md.
 */
const _measureCache = new Map();

/**
 * Math configs to re-render when KaTeX faces (lazily) (re)load. Keyed by
 * svgEl so repeated render() calls de-dupe instead of stacking — this keeps
 * the queue re-armable across many `loadingdone` events; it never permanently
 * disarms the way the old `_fontsReady` short-circuit did.
 * @type {Map<SVGElement, { svgEl: SVGElement, config: Object, renderFn: Function }>}
 */
const _mathReRenders = new Map();

/** The FontFaceSet we've attached listeners to (re-arm only if it changes). */
let _watchedFontSet = null;

/** Handle for the bounded backstop timer (see armFontWatch). */
let _backstopTimer = null;

/**
 * Final unconditional correction for the tail case where no font event ever
 * fires (a CDN whose loadingdone never resolves, an engine that doesn't
 * retro-load faces for already-laid-out content, or a diagram measured then
 * hidden). The recurring loadingdone path handles the common case; this only
 * bounds the worst case. It is the single tunable constant in this module.
 */
const FONT_CORRECTION_BACKSTOP_MS = 8000;

/** True for FontFace families belonging to KaTeX (KaTeX_Main, _Math, _AMS…). */
function isKatexFamily(family) {
  return typeof family === 'string' && /^['"]?\s*KaTeX/i.test(family);
}

/**
 * Force-resolve every KaTeX face the layout is already pulling in ('loading')
 * or already has ('loaded'); the returned promise settles when they are
 * usable. 'unloaded' faces are intentionally skipped so a page with a single
 * `$x$` never force-downloads all of KaTeX's font files.
 * @param {FontFaceSet} fonts
 * @returns {Promise}
 */
function loadActiveKatexFaces(fonts) {
  const loads = [];
  fonts.forEach((face) => {
    if (isKatexFamily(face.family) && (face.status === 'loading' || face.status === 'loaded')) {
      loads.push(Promise.resolve(face.load()).catch(() => {}));
    }
  });
  return loads.length ? Promise.all(loads) : Promise.resolve();
}

/**
 * Are all KaTeX faces settled? False while any is mid-flight ('loading') —
 * a measurement taken then would use fallback metrics.
 * @param {FontFaceSet} fonts
 * @returns {boolean}
 */
function katexFacesSettled(fonts) {
  let settled = true;
  fonts.forEach((face) => {
    if (isKatexFamily(face.family) && face.status === 'loading') settled = false;
  });
  return settled;
}

/** Clear memoized metrics and re-render every registered math config. */
function flushFontCorrection() {
  _measureCache.clear();
  // Snapshot: each renderFn re-registers itself (idempotently by svgEl), so
  // the queue survives this pass and stays armed for later font batches.
  for (const entry of Array.from(_mathReRenders.values())) {
    try { entry.renderFn(entry.svgEl, entry.config); } catch { /* keep going */ }
  }
}

/**
 * Attach FontFaceSet listeners once per FontFaceSet instance. Re-arms if
 * `document.fonts` is swapped (tests inject a fake; production never swaps).
 */
function armFontWatch() {
  if (typeof document === 'undefined' || !document.fonts) return;
  const fonts = document.fonts;
  if (fonts === _watchedFontSet) return;
  _watchedFontSet = fonts;
  _mathReRenders.clear();   // new font environment → drop stale registrations
  _measureCache.clear();
  if (_backstopTimer != null) { clearTimeout(_backstopTimer); _backstopTimer = null; }

  // (1) Converge on the RECURRING loadingdone event: KaTeX faces arrive in
  //     several lazy batches (Main, then Math, then maybe AMS), and each
  //     KaTeX batch invalidates the cache and re-fits every math diagram.
  if (typeof fonts.addEventListener === 'function') {
    fonts.addEventListener('loadingdone', (ev) => {
      const batch = ev && ev.fontfaces;
      const involvesKatex = !batch || batch.length === 0
        ? true                                          // some engines leave it empty
        : batch.some((f) => isKatexFamily(f.family));
      if (!involvesKatex) return;                       // ignore unrelated page fonts
      loadActiveKatexFaces(fonts).then(flushFontCorrection);
    });
  }
  // (2) fonts.ready as a one-shot HINT, never an authority: a guaranteed
  //     second paint that also upgrades a plain-text fallback to math if
  //     KaTeX's JS loaded late. Runs even on an already-resolved promise.
  if (fonts.ready && typeof fonts.ready.then === 'function') {
    fonts.ready.then(() => loadActiveKatexFaces(fonts).then(flushFontCorrection));
  }
  // (3) Bounded backstop for the tail case where no font event ever fires.
  _backstopTimer = setTimeout(flushFontCorrection, FONT_CORRECTION_BACKSTOP_MS);
  if (_backstopTimer && typeof _backstopTimer.unref === 'function') _backstopTimer.unref();
}

/**
 * Register a render for re-execution when KaTeX web fonts (lazily) (re)load.
 * Re-armable: keyed by svgEl, so the flush-driven re-renders refresh their own
 * entry instead of multiplying, and the queue never permanently disarms.
 * @param {SVGElement} svgEl
 * @param {Object} config
 * @param {Function} renderFn
 */
export function registerPendingReRender(svgEl, config, renderFn) {
  if (typeof document === 'undefined' || !document.fonts) return; // SSR/jsdom: nothing to wait on
  armFontWatch();
  _mathReRenders.set(svgEl, { svgEl, config, renderFn });
}

/**
 * Reset all font-correction state. Test-only hook: jsdom does not implement
 * `document.fonts`, so tests inject a fake FontFaceSet and reset between cases.
 */
export function __resetFontReadiness() {
  _measureCache.clear();
  _mathReRenders.clear();
  _watchedFontSet = null;
  if (_backstopTimer != null) { clearTimeout(_backstopTimer); _backstopTimer = null; }
}

/**
 * Measure rendered KaTeX HTML dimensions.
 * @param {string} html - KaTeX HTML string
 * @param {number} fontSize
 * @returns {{ width: number, height: number }}
 */
function measureKaTeXHTML(html, fontSize) {
  const key = `${fontSize} ${html}`;
  const cached = _measureCache.get(key);
  if (cached) return cached;

  const div = getMeasureDiv();
  div.style.fontSize = `${fontSize}px`;
  div.innerHTML = html;
  const rect = div.getBoundingClientRect();
  const dim = { width: rect.width, height: rect.height };
  // Return a measurement for the current paint, but only PIN it once the KaTeX
  // faces have settled — a pre-font (fallback-metric) measurement is never
  // memoized permanently, so the next loadingdone flush re-measures it. (Zero
  // dims mean a hidden/unstyled element; never cache those either.)
  const fonts = typeof document !== 'undefined' ? document.fonts : null;
  const settled = !fonts || katexFacesSettled(fonts);
  if ((dim.width > 0 || dim.height > 0) && settled) _measureCache.set(key, dim);
  return dim;
}

// ── Public API ──────────────────────────────────────────

/**
 * Create label content — either KaTeX foreignObject or plain text fallback.
 *
 * @param {string} label
 * @param {{ fontSize: number, fontFamily: string, color: string }} opts
 * @returns {{ type: 'math'|'text', content: string, html?: string, width: number, height: number }}
 */
export function createLabelContent(label, opts) {
  const { fontSize = 14, fontFamily = 'serif', color = '#000' } = opts;
  const str = String(label);

  if (isMathLabel(str) && isKaTeXAvailable()) {
    const html = renderMathToHTML(str);
    const dim = measureKaTeXHTML(html, fontSize);
    // Estimate from TeX content length if measurement fails (e.g. hidden element)
    const texContent = stripMath(str);
    const estWidth = texContent.length * fontSize * 0.7;
    const estHeight = fontSize * 1.8;
    // Add padding to prevent clipping at foreignObject boundaries
    const pad = fontSize * 0.4;
    return {
      type: 'math',
      content: str,
      html,
      width: (dim.width > 0 ? dim.width : estWidth) + pad,
      height: (dim.height > 0 ? dim.height : estHeight) + pad,
    };
  }

  // Fallback: plain text (strip $ if present)
  const text = isMathLabel(str) ? stripMath(str) : str;
  const charWidth = fontSize * 0.6;
  return {
    type: 'text',
    content: text,
    width: text.length * charWidth,
    height: fontSize * 1.2,
  };
}

/**
 * Build a <foreignObject> SVG element containing KaTeX-rendered HTML.
 * Centered at origin (for use inside a translated <g>).
 * @param {string} html - KaTeX HTML
 * @param {number} width
 * @param {number} height
 * @param {{ fontSize: number, color: string }} opts
 * @returns {SVGForeignObjectElement}
 */
export function createMathForeignObject(html, width, height, opts) {
  const { fontSize = 14, color = '#000' } = opts;

  const fo = document.createElementNS(SVG_NS, 'foreignObject');
  fo.setAttribute('x', -width / 2);
  fo.setAttribute('y', -height / 2);
  fo.setAttribute('width', width);
  fo.setAttribute('height', height);
  fo.setAttribute('overflow', 'visible');

  const div = document.createElementNS(XHTML_NS, 'div');
  div.setAttribute('xmlns', XHTML_NS);
  div.style.fontSize = `${fontSize}px`;
  div.style.color = color;
  div.style.display = 'flex';
  div.style.alignItems = 'center';
  div.style.justifyContent = 'center';
  div.style.width = '100%';
  div.style.height = '100%';
  div.style.lineHeight = '1';
  div.innerHTML = html;

  fo.appendChild(div);
  return fo;
}
